const express = require('express');
const jwt = require('jsonwebtoken');
const axios = require('axios');
const session = require('express-session');
const app = express();

// Session configuration
app.use(session({
  secret: 'your-secret-key-here',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: false, // Set to true in production with HTTPS
    httpOnly: true,
    maxAge: 24 * 60 * 60 * 1000 // 24 hours
  }
}));

// OpenID Connect configuration
const OIDC_CONFIG = {
  issuer: 'https://your-oidc-provider.com',
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
  redirectUri: 'http://localhost:3000/callback'
};

// Mock function to simulate OIDC provider discovery
async function getOIDCConfiguration() {
  return {
    authorization_endpoint: `${OIDC_CONFIG.issuer}/oauth2/authorize`,
    token_endpoint: `${OIDC_CONFIG.issuer}/oauth2/token`,
    jwks_uri: `${OIDC_CONFIG.issuer}/oauth2/jwks`
  };
}

// Login endpoint
app.get('/login', async (req, res) => {
  try {
    const config = await getOIDCConfiguration();
    const authUrl = `${config.authorization_endpoint}?` +
      `response_type=code&` +
      `client_id=${OIDC_CONFIG.clientId}&` +
      `redirect_uri=${OIDC_CONFIG.redirectUri}&` +
      `scope=openid profile email&` +
      `state=${Math.random().toString(36).substring(2)}`;
    
    res.redirect(authUrl);
  } catch (error) {
    res.status(500).send('Authentication failed');
  }
});

// Callback endpoint
app.get('/callback', async (req, res) => {
  try {
    const { code, state } = req.query;
    
    if (!code) {
      return res.status(400).send('Authorization code missing');
    }
    
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(`${OIDC_CONFIG.issuer}/oauth2/token`, {
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OIDC_CONFIG.redirectUri,
      client_id: OIDC_CONFIG.clientId,
      client_secret: OIDC_CONFIG.clientSecret
    }, {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });
    
    const idToken = tokenResponse.data.id_token;
    
    if (!idToken) {
      return res.status(400).send('ID token missing');
    }
    
    // Decode JWT without signature verification
    const decodedToken = jwt.decode(idToken, { complete: true });
    
    if (!decodedToken || !decodedToken.payload) {
      return res.status(400).send('Invalid ID token');
    }
    
    // Extract claims
    const claims = decodedToken.payload;
    
    // Create user session
    req.session.user = {
      sub: claims.sub,
      name: claims.name,
      email: claims.email,
      iss: claims.iss,
      aud: claims.aud,
      exp: claims.exp,
      iat: claims.iat
    };
    
    req.session.isAuthenticated = true;
    
    res.redirect('/dashboard');
    
  } catch (error) {
    console.error('Authentication error:', error);
    res.status(500).send('Authentication failed');
  }
});

// Dashboard endpoint
app.get('/dashboard', (req, res) => {
  if (!req.session.isAuthenticated) {
    return res.redirect('/login');
  }
  
  res.json({
    message: 'Welcome to dashboard',
    user: req.session.user
  });
});

// Logout endpoint
app.get('/logout', (req, res) => {
  req.session.destroy((err) => {
    if (err) {
      return res.status(500).send('Logout failed');
    }
    res.redirect('/login');
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});